/** The logo glyph for a backend kind. */
function BackendLogo({ kind, size = 16 }: { kind: string; size?: number }) {
  switch (kind) {
    case "modal_job":
      return <ModalLogo size={size} />;
    case "hf_job":
      return <HuggingFaceLogo size={size} />;
    case "k8s_job":
      return <KubernetesLogo size={size} />;
    case "ssh_job":
      return <Server size={size} />;
    case "slurm_job":
      return <Boxes size={size} />;
    case "openresearch_job":
      return <Cloud size={size} />;
    case "local_job":
      return <Laptop size={size} />;
    default:
      return <Server size={size} />;
  }
}

/** Logo + detail (flavor/host), the cell used in the instances table. */
export function BackendBadge({ backend }: { backend: Run["backend"] }) {
  const kind = backendKind(backend);
  const detail = backendDetail(backend);
  if (!kind) return <span className="backend-badge muted">—</span>;
  return (
    <span className="backend-badge">
      <BackendLogo kind={kind} />
      <span className="backend-name">{backendName(kind)}</span>
      {detail && <span className="backend-detail mono">{detail}</span>}
    </span>
  );
}
